#include <bits/stdc++.h>
using namespace std;

const int MOD = 1e9 + 7;

int countSubsequences(string& s1, string& s2) {
    int n = s1.length();
    int m = s2.length();

    vector<vector<long long>> dp(n + 1, vector<long long>(m + 1, 0));

    for(int i = 0; i <= n; i++) {
        dp[i][0] = 1;
    }

    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= m; j++) {
            if(s1[i-1] == s2[j-1]) {
                dp[i][j] = (dp[i-1][j-1] + dp[i-1][j]) % MOD;
            }
            else {
                dp[i][j] = dp[i-1][j];
            }
        }
    }

    return dp[n][m];
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        string s1, s2;
        cin >> s1 >> s2;
        cout << countSubsequences(s1, s2) << endl;
    }

    return 0;
}
